import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import { 
  Table, 
  Avatar, 
  Tag, 
  Card, 
  Typography, 
  Space, 
  Button, 
  Badge, 
  theme, 
  Modal, 
  Form, 
  Input, 
  Select, 
  Drawer, 
  Descriptions, 
  Progress,
  Flex,
  Divider,
  message,
  TimePicker 
} from "antd";
import dayjs from "dayjs";
import { 
  UserOutlined, 
  MobileOutlined, 
  PlusOutlined, 
  EditOutlined, 
  DeleteOutlined, 
  SendOutlined,
  ExclamationCircleOutlined,
  InfoCircleOutlined,
  FilterOutlined,
  SearchOutlined,
  FileTextOutlined,
  ReloadOutlined,
  CaretRightOutlined,
  DisconnectOutlined,
  CloseOutlined
} from "@ant-design/icons";
import { QUARANTINE_DB } from "../../../mocks/db";

const { Title, Text } = Typography;
const { confirm } = Modal;

const AgentManagementPage: React.FC = () => {
  const { t } = useTranslation(["quarantine", "management", "common", "scenario"]);
  const { token } = theme.useToken();
  const [selectedRowKeys, setSelectedRowKeys] = useState<React.Key[]>([]);

  // Utility States
  const [showSearch, setShowSearch] = useState(false);
  const [searchKeyword, setSearchKeyword] = useState("");

  // Modal & Drawer States
  const [isAgentModalOpen, setIsAgentModalOpen] = useState(false);
  const [isPushModalOpen, setIsPushModalOpen] = useState(false);
  const [isDetailOpen, setIsDetailOpen] = useState(false);
  const [modalMode, setModalMode] = useState<"add" | "edit">("add");
  const [activeAgent, setActiveAgent] = useState<any>(null);

  const [agentForm] = Form.useForm();
  const [pushForm] = Form.useForm();

  // Mock Active Data
  const [agents] = useState(QUARANTINE_DB.agents);

  const filteredAgents = agents.filter(a => 
    a.name.toLowerCase().includes(searchKeyword.toLowerCase()) || 
    a.id.toLowerCase().includes(searchKeyword.toLowerCase())
  );

  const handleAgentAction = (mode: "add" | "edit", target?: any) => {
    setModalMode(mode);
    if (mode === "edit" && target) {
      setActiveAgent(target);
      const shiftTime = target.shiftTime ? target.shiftTime.split(' - ').map((t: string) => dayjs(t, 'HH:mm')) : null;
      agentForm.setFieldsValue({ ...target, shiftTime });
    } else {
      setActiveAgent(null);
      agentForm.resetFields();
    }
    setIsAgentModalOpen(true);
  };

  const handlePushAction = (agent: any) => {
    setActiveAgent(agent);
    pushForm.resetFields();
    setIsPushModalOpen(true);
  };

  const handleDetailAction = (agent: any) => {
    setActiveAgent(agent);
    setIsDetailOpen(true);
  };

  const handleDelete = () => {
    confirm({
      title: t("common:confirmDelete"),
      icon: <ExclamationCircleOutlined />,
      content: t("common:deleteWarning"),
      okText: t("common:yes"),
      cancelText: t("common:no"),
      onOk() {
        message.success(t("common:deleteSuccess"));
      },
    });
  };

  const handleRefresh = () => {
    const hide = message.loading(t("management:refresh") + "...", 0);
    setTimeout(() => {
      hide();
      message.success(t("management:cmdSent"));
    }, 800);
  };

  const columns = [
    {
      title: t("scenario:name"),
      key: "name",
      render: (_: any, record: any) => (
        <Space size="middle">
          <Avatar icon={<UserOutlined />} style={{ background: token.colorPrimary, color: token.colorTextLightSolid }} />
          <div>
            <Text style={{ display: "block", color: token.colorText, fontWeight: "bold", fontSize: 13 }}>{t(`scenario:${record.name}`)}</Text>
            <Text style={{ color: token.colorTextDescription, fontSize: 11, fontStyle: 'italic' }}>{record.id}</Text>
          </div>
        </Space>
      ),
    },
    { title: t("scenario:role"), dataIndex: "role", key: "role", render: (val: string) => <Tag color="blue" variant="filled" style={{ fontSize: 10 }}>{t(`scenario:role_${val}`) || t(`scenario:${val}`)}</Tag> },
    { title: t("scenario:rank"), dataIndex: "rank", key: "rank", render: (val: string) => <Text style={{ fontSize: 13, color: token.colorTextSecondary }}>{t(`scenario:${val}`)}</Text> },
    { title: t("scenario:department"), dataIndex: "department", key: "department", render: (val: string) => <Text style={{ fontSize: 12 }}>{t(`scenario:dept_${val}`) || t(`scenario:${val}`)}</Text> },
    { 
      title: t("scenario:assigned"), 
      dataIndex: "assigned", 
      key: "assigned",
      render: (val: string) => <Tag variant="filled" style={{ background: `${token.colorPrimary}15`, color: token.colorPrimary, fontSize: 11 }}>{val}</Tag>
    },
    { title: t("scenario:shiftTime"), dataIndex: "shiftTime", key: "shiftTime", render: (val: string) => <Text style={{ fontSize: 12, color: token.colorTextDescription }}>{val}</Text> },
    {
      title: t("management:status"),
      dataIndex: "appStatus",
      render: (status: string) => (
        <Badge status={status === "online" ? "processing" : "default"} text={<span style={{ color: token.colorTextDescription, fontSize: 12 }}>{status === "online" ? t("quarantine:common.online") : t("quarantine:common.offline")}</span>} />
      ),
    },
    {
      title: t("common:actions"),
      key: "actions",
      align: "center" as const,
      render: (_: any, record: any) => (
        <Space>
          <Button size="small" icon={<MobileOutlined />} className="btn-vibrant-info h-8 px-3" onClick={() => handlePushAction(record)} style={{ fontSize: 11 }}>{t("management:pushNotification").split(' ')[0]}</Button>
          <Button size="small" icon={<InfoCircleOutlined />} className="btn-vibrant-secondary h-8 px-3" onClick={() => handleDetailAction(record)} style={{ fontSize: 11 }}>{t("common:detail")}</Button>
        </Space>
      )
    }
  ];

  return (
    <div className="p-6 h-full flex flex-col relative" style={{ background: token.colorBgLayout }}>
      <Flex justify="space-between" align="center" className="mb-6">
        <Title level={4} className="m-0 font-bold" style={{ color: token.colorText }}>
          {t("quarantine:navigation.agentMng")}
        </Title>
        <Space size="middle">
          <Space size={2} className="p-0.5 px-2 rounded-lg border transition-all" style={{ background: token.colorBgLayout, borderColor: token.colorBorderSecondary }}>
             <Button type="text" size="small" icon={<SearchOutlined />} className="btn-utility" onClick={() => setShowSearch(!showSearch)} />
             <Button type="text" size="small" icon={<FileTextOutlined />} className="btn-utility" onClick={() => message.success(t("management:reportGenerated"))} />
          </Space>
          {showSearch && (
            <Input 
              size="small" 
              placeholder={t("management:searchPlaceholder")} 
              className="animate-in fade-in slide-in-from-left-2"
              style={{ width: 150, borderRadius: 6, background: 'rgba(0,0,0,0.2)' }} 
              value={searchKeyword}
              onChange={(e) => setSearchKeyword(e.target.value)}
              autoFocus
            />
          )}
           <Divider orientation="vertical" />
           <Space size="small">
              {[
                { label: t("management:refresh"), icon: <ReloadOutlined />, className: "btn-vibrant-primary", onClick: handleRefresh },
                { label: t("management:add"), icon: <PlusOutlined />, className: "btn-vibrant-primary", onClick: () => handleAgentAction("add") },
                { label: t("management:edit"), icon: <EditOutlined />, className: "btn-vibrant-primary", onClick: () => handleAgentAction("edit", agents[0]) },
                { label: t("management:delete"), icon: <DeleteOutlined />, className: "btn-vibrant-secondary", onClick: handleDelete },
              ].map(btn => (
                 <Button 
                   key={btn.label}
                   className={`${btn.className || "btn-vibrant-primary"} border-none h-8 px-4`}
                   icon={btn.icon}
                   onClick={(btn as any).onClick}
                 >
                   {btn.label}
                 </Button>
              ))}
           </Space>
        </Space>
      </Flex>

      <Card 
        variant="borderless" 
        className="shadow-sm flex-1 overflow-hidden" 
        style={{ background: token.colorBgContainer, borderRadius: 16 }}
        styles={{ body: { padding: 0, height: '100%', display: 'flex', flexDirection: 'column' } }}
      >
        <Table 
          rowSelection={{ type: 'checkbox', selectedRowKeys, onChange: (k) => setSelectedRowKeys(k) }}
          columns={columns} 
          dataSource={filteredAgents.map(a => ({ ...a, key: a.id }))} 
          pagination={{ pageSize: 12 }}
          className="custom-table"
          size="middle"
          scroll={{ y: 'calc(100vh - 320px)' }}
        />
      </Card>

      {/* --- Agent Modal (Add/Edit) --- */}
      <Modal
        title={<Text className="font-bold ml-2" style={{ color: token.colorText, fontSize: 18 }}>{modalMode === "add" ? t("management:addAgent") : t("management:editAgent")}</Text>}
        open={isAgentModalOpen}
        onCancel={() => setIsAgentModalOpen(false)}
        footer={(
          <Flex justify="end" gap={12} className="p-6 pt-0">
            <Button className="btn-vibrant-secondary h-11 px-10" onClick={() => setIsAgentModalOpen(false)}>
              {t("common:no")}
            </Button>
            <Button className="btn-vibrant-primary h-11 px-10" onClick={() => { 
              const values = agentForm.getFieldsValue();
              const formattedTime = values.shiftTime ? `${values.shiftTime[0].format('HH:mm')} - ${values.shiftTime[1].format('HH:mm')}` : "";
              message.success(t("common:saveSuccess")); 
              setIsAgentModalOpen(false); 
              console.log("Saving agent with time:", formattedTime);
            }}>
              {t("common:yes")}
            </Button>
          </Flex>
        )}
        centered
        width={600}
        styles={{ 
          mask: { backdropFilter: "blur(12px)" }, 
          body: { padding: "32px 24px" },
          header: { padding: "24px 24px 0", marginBottom: 0 }
        }}
        closeIcon={<CloseOutlined style={{ color: token.colorTextQuaternary }} />}
      >
        <Form form={agentForm} layout="vertical" className="space-y-4">
          <Form.Item name="name" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("scenario:name")}</Text>} rules={[{ required: true }]}>
            <Input style={{ height: 42, background: token.colorBgLayout, borderRadius: 6 }} />
          </Form.Item>
          <Form.Item name="role" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("scenario:role")}</Text>}>
            <Select style={{ height: 42 }} options={[{ value: 'role_leader', label: t("scenario:role_leader") }, { value: 'role_security', label: t("scenario:role_security") }]} />
          </Form.Item>
          <Form.Item name="department" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("scenario:department")}</Text>}>
             <Select style={{ height: 42 }} options={[{ value: 'dept_quarantine', label: t("scenario:dept_quarantine") }, { value: 'dept_security', label: t("scenario:dept_security") }]} />
          </Form.Item>
          <Form.Item name="shiftTime" label={<Text strong style={{ color: token.colorTextSecondary }}>{t("scenario:shiftTime")}</Text>}>
            <TimePicker.RangePicker 
              format="HH:mm" 
              className="w-full"
              style={{ height: 42, background: token.colorBgLayout, border: `1px solid ${token.colorBorderSecondary}`, borderRadius: 6 }} 
              popupClassName="custom-timepicker-popup"
            />
          </Form.Item>
        </Form>
      </Modal>

      {/* --- PUSH Modal --- */}
      <Modal
        title={<Text className="font-bold ml-2" style={{ color: token.colorText, fontSize: 18 }}>{t("management:pushNotification")}</Text>}
        open={isPushModalOpen}
        onCancel={() => setIsPushModalOpen(false)}
        footer={(
          <Flex justify="end" gap={12} className="p-6 pt-0">
            <Button className="btn-vibrant-secondary h-11 px-10" onClick={() => setIsPushModalOpen(false)}>
              {t("common:cancel")}
            </Button>
            <Button className="btn-vibrant-primary h-11 px-10" onClick={() => { message.success("PUSH dispatch confirmed"); setIsPushModalOpen(false); }}>
              {t("management:sendMission")}
            </Button>
          </Flex>
        )}
        centered
        width={500}
        styles={{ 
          mask: { backdropFilter: "blur(12px)" }, 
          body: { padding: "32px 24px" },
          header: { padding: "24px 24px 0", marginBottom: 0 }
        }}
        closeIcon={<CloseOutlined style={{ color: token.colorTextQuaternary }} />}
      >
        <div className="py-4 space-y-6">
           <div className="p-4 rounded-xl border flex items-center justify-between" style={{ background: token.colorFillAlter, borderColor: token.colorBorderSecondary }}>
              <Text strong style={{ color: token.colorTextSecondary }}>{t("management:recipients")}</Text>
              <Tag color="blue" className="btn-vibrant-info border-none px-4 py-1 font-bold" style={{ borderRadius: 6 }}>{activeAgent?.name} ({activeAgent?.id})</Tag>
           </div>
           <Form form={pushForm} layout="vertical" className="space-y-4">
              <Form.Item label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:actionMessage")}</Text>} name="message" rules={[{ required: true }]}>
                 <Input.TextArea rows={4} style={{ background: token.colorBgLayout, borderRadius: 6 }} placeholder={t("management:tacticalInstruction") || "Enter instructions..."} />
              </Form.Item>
              <Form.Item label={<Text strong style={{ color: token.colorTextSecondary }}>{t("management:urgency")}</Text>} name="urgency">
                 <Select style={{ height: 42 }} defaultValue="normal" options={[
                   { value: 'emergency', label: t("management:emergency") },
                   { value: 'normal', label: t("management:normalMission") },
                   { value: 'info', label: t("common:info") || 'Information' }
                 ]} />
              </Form.Item>
           </Form>
        </div>
      </Modal>

      {/* --- Detail Drawer --- */}
      <Drawer
        title={t("management:tacticalProfile")}
        placement="right"
        size="default"
        onClose={() => setIsDetailOpen(false)}
        open={isDetailOpen}
        styles={{ header: { background: token.colorFillAlter }, body: { background: token.colorBgLayout } }}
      >
        {activeAgent && (
          <div className="flex flex-col gap-6">
             <div className="text-center p-6 bg-black/20 rounded-2xl border border-white/5">
                <Avatar size={80} icon={<UserOutlined />} style={{ background: token.colorPrimary, marginBottom: 16 }} />
                <Title level={4} className="m-0">{activeAgent.name}</Title>
                <Text type="secondary">{activeAgent.id}</Text>
                <div className="mt-4 flex justify-center gap-2">
                   <Tag color="gold">{activeAgent.rank}</Tag>
                   <Tag color="cyan">{t(`scenario:${activeAgent.role}`)}</Tag>
                </div>
             </div>

             <Descriptions title={t("management:operationalStatus")} column={1} bordered size="small" className="bg-black/10 p-4 rounded-xl border-white/5">
                <Descriptions.Item label={t("management:currentLocation")}>{activeAgent.assigned}</Descriptions.Item>
                <Descriptions.Item label={t("scenario:department")}>{t(`scenario:${activeAgent.department}`)}</Descriptions.Item>
                <Descriptions.Item label={t("scenario:shiftTime")}>{activeAgent.shiftTime}</Descriptions.Item>
                <Descriptions.Item label={t("management:status")}>
                   <Badge status={activeAgent.appStatus === "online" ? "processing" : "default"} text={<span style={{ color: token.colorTextSecondary }}>{activeAgent.appStatus === "online" ? t("quarantine:common.online") : t("quarantine:common.offline")}</span>} />
                </Descriptions.Item>
                <Descriptions.Item label={t("management:lastSyncTime")}>{`10 ${t("management:minutes")} ${t("management:ago")}`}</Descriptions.Item>
                <Descriptions.Item label={t("management:battery")}>
                   <Space>
                      <Progress percent={85} size="small" status="active" style={{ width: 80 }} />
                      <Text style={{ fontSize: 12 }}>85%</Text>
                   </Space>
                </Descriptions.Item>
             </Descriptions>

             <Card size="small" title={t("management:recentActivity")} style={{ background: 'transparent' }}>
                <div className="flex flex-col gap-3">
                   {[1, 2, 3].map(i => (
                     <div key={i} className="p-3 bg-white/5 rounded-lg border border-white/5">
                        <Text style={{ fontSize: 11, color: token.colorTextQuaternary, display: 'block' }}>2024-04-20 1{i}:24:00</Text>
                        <Text style={{ fontSize: 13 }}>G12 Gate area sanitization complete</Text>
                     </div>
                   ))}
                </div>
             </Card>
          </div>
        )}
      </Drawer>

      <style>{`
        .custom-table .ant-table { background: transparent !important; }
        .custom-table .ant-table-thead > tr > th { 
          background: ${token.colorFillAlter} !important; 
          color: ${token.colorTextSecondary} !important; 
          font-size: 11px !important; 
          font-weight: 900 !important;
          border-bottom: 2px solid ${token.colorBorderSecondary} !important;
          text-transform: none;
          text-align: center !important;
        }
        .custom-table .ant-table-tbody > tr > td { 
           border-bottom: 1px solid ${token.colorBorderSecondary} !important; 
           padding: 12px 16px !important; 
           text-align: center !important;
           background: transparent !important;
        }
        .custom-table .ant-table-row:hover > td { background: ${token.colorFillAlter} !important; cursor: pointer; }
        
        .ant-checkbox-inner { background: transparent !important; border: 1px solid ${token.colorBorder} !important; border-radius: 4px !important; }
        .ant-checkbox-checked .ant-checkbox-inner { background: ${token.colorPrimary} !important; border-color: ${token.colorPrimary} !important; }

        /* Solid Button System (High Contrast & Unified Blue - Per User Screenshot) */
        .btn-vibrant-primary, .btn-vibrant-secondary, .btn-vibrant-danger, .btn-vibrant-info, .btn-vibrant-warning { 
          background: ${token.colorPrimary} !important; 
          border-color: ${token.colorPrimary} !important; 
          color: #fff !important; 
          font-weight: bold !important; 
          border-radius: 6px !important; 
          transition: all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        }

        .btn-vibrant-primary:hover {
          filter: brightness(1.1) saturate(1.1);
          box-shadow: 0 4px 12px ${token.colorPrimary}40;
          transform: translateY(-1px);
        }
        .btn-vibrant-secondary {
          background: ${token.colorFillAlter} !important;
          border: 1px solid ${token.colorBorderSecondary} !important;
          color: ${token.colorTextDescription} !important;
          font-weight: bold !important;
          border-radius: 6px !important;
          transition: all 0.2s ease;
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .btn-vibrant-secondary:hover {
          background: ${token.colorFillSecondary} !important;
          color: ${token.colorText} !important;
          border-color: ${token.colorBorder} !important;
        }

        .btn-utility {
          color: ${token.colorTextQuaternary} !important;
          padding: 0 4px !important;
          border-radius: 4px !important;
          transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        }
        .btn-utility:hover { 
          color: ${token.colorPrimary} !important; 
          background: ${token.colorPrimary}1a !important; 
          transform: scale(1.2);
          filter: drop-shadow(0 0 5px ${token.colorPrimary}40);
        }

        @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
        @keyframes slide-in-from-left-2 { from { transform: translateX(-8px); } to { transform: translateX(0); } }
        .animate-in { animation: fade-in 0.3s ease-out; }
        .slide-in-from-left-2 { animation: slide-in-from-left-2 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275); }

        .custom-timepicker-popup .ant-picker-panel-container { 
          background: ${token.colorBgElevated} !important; 
          border: 1px solid ${token.colorBorderSecondary} !important; 
          border-radius: 12px !important; 
          box-shadow: 0 8px 32px rgba(0,0,0,0.5) !important;
        }
        .custom-timepicker-popup .ant-picker-time-panel-column > li.ant-picker-time-panel-cell-selected .ant-picker-time-panel-cell-inner {
          background: ${token.colorPrimary}20 !important;
          color: ${token.colorPrimary} !important;
        }
      `}</style>
    </div>
  );
};

export default AgentManagementPage;
